from qiskit.quantum_info import Pauli
p = Pauli('XYZ')
factors = {i: p[i].to_label() for i in range(p.num_qubits)}
true_q = next(i for i, lbl in factors.items() if lbl == "Z")
claims = {"D": 0, "A": 2, "B": 1}
evidence = {}
proven = []
for k, qi in claims.items():
    match = (true_q == qi)
    evidence[k] = f"per-qubit factors {factors}; Z is on qubit {true_q}; option {k} claims qubit {qi} -> match={match}"
    if match:
        proven.append(k)
evidence["C"] = f"Z is one tensor factor on qubit {true_q} only, not all three qubits -> claim False"
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"factors": factors, "z_qubit": true_q}})
